public void post(IFRUniversalInterfaceSystemPostContract _contract)
{        
    SetEnumerator			            se;
    Common					            record;
    #OCCRetryCount

    guid processGuid = newGuid();

    if (conLen(_contract.parmRecordCon()) > 0)
    {                
        se = Set::create(_contract.parmRecordCon()).getEnumerator();
        while (se.moveNext())
        {
            record = se.current();

            try
            {
                if (this.processRecord(record, processGuid))
                {
                    ttsBegin;
                    this.markRecordAsProcessed(record, processGuid);
                    ttsCommit;
                } 
            }
            catch (Exception::Deadlock)
            {
                retry;
            }
            catch (Exception::UpdateConflict)
            {
                if (appl.ttsLevel() == 0)
                {
                    if (xSession::currentRetryCount() >= #RetryNum)
                    {
                        throw Exception::UpdateConflictNotRecovered;
                    }
                    else
                    {
                        retry;
                    }
                }
                else
                {
                    throw Exception::UpdateConflict;
                }
            }
            catch (Exception::Error)
            {
                IFRUniversalInterfaceSystemTable ifrUniversalInterfaceSystemTable;

                ttsbegin;

                while select ifrUniversalInterfaceSystemTable
                    where ifrUniversalInterfaceSystemTable.ExecutionId  == processGuid
                        && ifrUniversalInterfaceSystemTable.RecId       == record.RecId
                {
                    ifrUniversalInterfaceSystemTable.writeInfoLogErrorData();
                }

                ttscommit;
            }
        }
    }                            
}

private void markRecordAsProcessed(Common _common, guid _processGuid)
{
    IFRUniversalInterfaceSystemTable ifrUniversalInterfaceSystemTable = IFRUniversalInterfaceSystemTable::findRecId(_common.RecId);

    if (ifrUniversalInterfaceSystemTable)
    {
        IFRUniversalInterfaceSystemTable::markRecordsAsProcessed(_processGuid, ifrUniversalInterfaceSystemTable.RecId);
    }
}
